const fs = require('fs');

const categories = ["전자제품", "의류", "도서", "식품", "가구", "패션잡화", "생활용품", "주방용품", "스포츠/레저", "뷰티"];
const brands = ["테크마스터", "네이처스베스트", "엘레강스", "컴포트존", "홈센스", "스타일핏", "사운드온", "꿈나무출판사", "셰프마스터", "에코그린"];
const colors = ["블랙", "화이트", "실버", "레드", "블루", "그레이", "브라운", "베이지", "골드", "핑크", "네이비", "우드", "해당없음"];
const materials = ["플라스틱", "금속", "인조가죽", "천연가죽", "면", "폴리에스터", "데님", "실리콘", "세라믹", "유리", "원목", "메쉬", "알루미늄", "종이", "스테인리스 스틸", "합성피혁", "패브릭", "고무", "해당없음"];
const sizes = {
    "의류": ["S", "M", "L", "XL", "28", "30", "32", "34", "36"],
    "도서": ["단일", "세트"],
    "식품": ["200g", "500g", "1kg", "1L", "3L"],
    "주방용품": ["소", "중", "대", "24cm", "28cm"],
    "가구": ["1인용", "2인용", "3인용", "단일"],
    "전자제품": ["단일", "1TB", "2TB"],
    "패션잡화": ["단일"],
    "생활용품": ["단일", "10ml", "30ml", "200ml", "500ml"],
    "스포츠/레저": ["단일", "S", "M", "L", "XL"],
    "뷰티": ["단일", "30ml", "50ml", "100ml"]
};

const products = [];

// 배열에서 무작위로 n개의 요소를 선택하는 헬퍼 함수
function getRandomElements(arr, num) {
    const shuffled = [...arr].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, num);
}

for (let i = 1; i <= 10000; i++) {
    const category = categories[Math.floor(Math.random() * categories.length)];
    const productNamePrefix = ["프리미엄", "고급", "유기농", "클래식", "모던", "베이직", "휴대용", "친환경", "스마트", "초고속"][Math.floor(Math.random() * 10)];
    const productNameSuffix = ["헤드폰", "시리얼", "지갑", "의자", "디퓨저", "티셔츠", "스피커", "그림책", "프라이팬", "세제", "워치", "커피", "토트백", "소파", "공기청정기", "청바지", "외장하드", "도서", "매트", "오일"][Math.floor(Math.random() * 20)];

    const product = {
        id: i,
        name: `${productNamePrefix} ${productNameSuffix}`,
        category: category,
        price: Math.floor(Math.random() * (1000000 - 10000 + 1)) + 10000,
        brand: brands[Math.floor(Math.random() * brands.length)],
        rating: parseFloat((Math.random() * (5.0 - 1.0) + 1.0).toFixed(1)),
        in_stock: Math.random() < 0.8, // 80% 확률로 재고 있음
        colors: (category === "도서" || category === "식품" || category === "생활용품") ? ["해당없음"] : getRandomElements(colors.filter(c => c !== "해당없음"), Math.floor(Math.random() * 3) + 1),
        materials: (category === "도서" || category === "식품" || category === "생활용품") ? ["해당없음"] : getRandomElements(materials.filter(m => m !== "해당없음"), Math.floor(Math.random() * 2) + 1),
        size: getRandomElements(sizes[category] || ["단일"], Math.floor(Math.random() * 3) + 1)
    };
    products.push(product);
}

// JSON 파일로 저장
fs.writeFile('products_10000.json', JSON.stringify(products, null, 2), 'utf8', (err) => {
    if (err) {
        console.error('파일 저장 중 오류 발생:', err);
        return;
    }
    console.log('10,000개의 상품 데이터가 products_10000.json 파일로 생성되었습니다.');
});

