+const fs = require('fs');
+const path = require('path');
+
+const TOTAL_PRODUCTS = 10000;
+const OUTPUT_FILES = [
+  path.resolve(process.cwd(), 'products_10000.json'),
+  path.resolve(process.cwd(), 'public/products_10000.json'),
+];
+
+const categories = [
+  '전자제품',
+  '과일',
+  '뷰티',
+  '패션',
+  '도서',
+  '생활용품',
+  '주방용품',
+  '스포츠/레저',
+  '가구',
+  '식품',
+];
+
+const productDescriptors = ['프리미엄', '데일리', '시그니처', '에센셜', '모던', '스마트', '라이트', '클래식'];
+
+const categoryKeywords = {
+  전자제품: ['노트북', '이어버드', '스피커', '모니터', '키보드'],
+  과일: ['사과', '배', '바나나', '오렌지', '블루베리'],
+  뷰티: ['세럼', '크림', '토너', '립밤', '마스크'],
+  패션: ['셔츠', '후디', '슬랙스', '스니커즈', '가디건'],
+  도서: ['소설', '에세이', '요리책', '개발서', '디자인북'],
+  생활용품: ['세제', '디퓨저', '수건', '보관함', '청소포'],
+  주방용품: ['프라이팬', '머그컵', '도마', '칼세트', '밀폐용기'],
+  '스포츠/레저': ['러닝화', '요가매트', '덤벨', '보틀', '캠핑체어'],
+  가구: ['책상', '의자', '서랍장', '스툴', '소파'],
+  식품: ['커피', '그래놀라', '파스타', '올리브오일', '차'],
+};
+
+function pickRandom(list) {
+  return list[Math.floor(Math.random() * list.length)];
+}
+
+function formatPrice() {
+  const price = Math.floor(Math.random() * (950000 - 5000 + 1)) + 5000;
+  return Math.round(price / 1000) * 1000;
+}
+
+function createProduct(id) {
+  const category = pickRandom(categories);
+  const keyword = pickRandom(categoryKeywords[category]);
+  const descriptor = pickRandom(productDescriptors);
+
+  return {
+    id,
+    name: `${descriptor} ${keyword}`,
+    category,
+    price: formatPrice(),
+  };
+}
+
+function writeJsonFile(filePath, data) {
+  fs.mkdirSync(path.dirname(filePath), { recursive: true });
+  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), 'utf8');
+}
+
+const products = Array.from({ length: TOTAL_PRODUCTS }, (_, index) => createProduct(index + 1));
+
+for (const filePath of OUTPUT_FILES) {
+  writeJsonFile(filePath, products);
+}
+
+console.log('10,000개의 상품 데이터가 products_10000.json 및 public/products_10000.json 파일로 생성되었습니다.');
