+import React from 'react';
+import { FilterPanel } from './components/FilterPanel';
+import { ProductList } from './components/ProductList';
+import { fetchProducts } from './lib/mockApi';
+import { filterProducts, serializeFiltersToSearch } from './lib/filters';
+import { useProductFilterStore } from './store/useProductFilterStore';
+import './App.css';
+
+function App() {
+  const status = useProductFilterStore((state) => state.status);
+  const errorMessage = useProductFilterStore((state) => state.errorMessage);
+  const products = useProductFilterStore((state) => state.products);
+  const availableCategories = useProductFilterStore((state) => state.availableCategories);
+  const searchTerm = useProductFilterStore((state) => state.searchTerm);
+  const selectedCategories = useProductFilterStore((state) => state.selectedCategories);
+  const selectedPriceRanges = useProductFilterStore((state) => state.selectedPriceRanges);
+  const hasHydratedFromUrl = useProductFilterStore((state) => state.hasHydratedFromUrl);
+  const hydrateFiltersFromUrl = useProductFilterStore((state) => state.hydrateFiltersFromUrl);
+  const setLoading = useProductFilterStore((state) => state.setLoading);
+  const setProducts = useProductFilterStore((state) => state.setProducts);
+  const setError = useProductFilterStore((state) => state.setError);
+
+  React.useEffect(() => {
+    hydrateFiltersFromUrl(window.location.search);
+  }, [hydrateFiltersFromUrl]);
+
+  React.useEffect(() => {
+    const controller = new AbortController();
+
+    async function loadProducts() {
+      setLoading();
+
+      try {
+        const loadedProducts = await fetchProducts(controller.signal);
+        setProducts(loadedProducts);
+      } catch (error) {
+        if (controller.signal.aborted) {
+          return;
+        }
+
+        const nextMessage = error instanceof Error ? error.message : '상품 데이터를 불러오지 못했습니다.';
+        setError(nextMessage);
+      }
+    }
+
+    loadProducts();
+
+    return () => controller.abort();
+  }, [setError, setLoading, setProducts]);
+
+  React.useEffect(() => {
+    if (!hasHydratedFromUrl) {
+      return;
+    }
+
+    const nextSearch = serializeFiltersToSearch({
+      searchTerm,
+      selectedCategories,
+      selectedPriceRanges,
+    });
+
+    const nextUrl = nextSearch ? `${window.location.pathname}?${nextSearch}` : window.location.pathname;
+    const currentUrl = `${window.location.pathname}${window.location.search}`;
+
+    if (nextUrl !== currentUrl) {
+      window.history.replaceState({}, '', nextUrl);
+    }
+  }, [hasHydratedFromUrl, searchTerm, selectedCategories, selectedPriceRanges]);
+
+  const filteredProducts = React.useMemo(
+    () =>
+      filterProducts(products, {
+        searchTerm,
+        selectedCategories,
+        selectedPriceRanges,
+      }),
+    [products, searchTerm, selectedCategories, selectedPriceRanges]
+  );
+
+  const activeFilterCount =
+    selectedCategories.length + selectedPriceRanges.length + (searchTerm.trim() ? 1 : 0);
