+export const PRICE_RANGES: PriceRange[] = [
+  { id: 'under-50000', label: '5만원 이하', min: 0, max: 50000 },
+  { id: '50000-150000', label: '5만원 - 15만원', min: 50000, max: 150000 },
+  { id: '150000-300000', label: '15만원 - 30만원', min: 150000, max: 300000 },
+  { id: '300000-600000', label: '30만원 - 60만원', min: 300000, max: 600000 },
+  { id: 'over-600000', label: '60만원 초과', min: 600000 },
+];
+
+function parseList(value: string | null) {
+  if (!value) {
+    return [];
+  }
+
+  return value
+    .split(',')
+    .map((entry) => entry.trim())
+    .filter(Boolean);
+}
+
+function normalizeList(values: string[]) {
+  return [...new Set(values)].sort((left, right) => left.localeCompare(right, 'ko-KR'));
+}
+
+export function prepareProducts(products: Product[]): PreparedProduct[] {
+  return products.map((product) => ({
+    ...product,
+    searchIndex: product.name.toLocaleLowerCase('ko-KR'),
+  }));
+}
+
+export function deriveCategories(products: Product[]) {
+  return normalizeList(products.map((product) => product.category));
+}
+
+export function parseFiltersFromSearch(search: string): FilterSnapshot {
+  const params = new URLSearchParams(search);
+
+  return {
+    searchTerm: params.get('q')?.trim() ?? '',
+    selectedCategories: normalizeList(parseList(params.get('categories'))),
+    selectedPriceRanges: normalizeList(parseList(params.get('prices'))),
+  };
+}
+
+export function serializeFiltersToSearch(filters: FilterSnapshot) {
+  const params = new URLSearchParams();
+
+  if (filters.searchTerm.trim()) {
+    params.set('q', filters.searchTerm.trim());
+  }
+
+  if (filters.selectedCategories.length) {
+    params.set('categories', normalizeList(filters.selectedCategories).join(','));
+  }
+
+  if (filters.selectedPriceRanges.length) {
+    params.set('prices', normalizeList(filters.selectedPriceRanges).join(','));
+  }
+
+  return params.toString();
+}
+
+function matchesPriceRange(price: number, rangeId: string) {
+  const range = PRICE_RANGES.find((entry) => entry.id === rangeId);
+
+  if (!range) {
+    return true;
+  }
+
+  const meetsMin = price >= range.min;
+  const meetsMax = typeof range.max === 'number' ? price < range.max : true;
+
+  return meetsMin && meetsMax;
+}
+
+export function filterProducts(products: PreparedProduct[], filters: FilterSnapshot) {
+  const normalizedQuery = filters.searchTerm.trim().toLocaleLowerCase('ko-KR');
+  const categorySet = filters.selectedCategories.length ? new Set(filters.selectedCategories) : null;
+  const priceRangeIds = filters.selectedPriceRanges;
+
+  return products.filter((product) => {
+    if (normalizedQuery && !product.searchIndex.includes(normalizedQuery)) {
+      return false;
+    }
+
+    if (categorySet && !categorySet.has(product.category)) {
+      return false;
+    }
+
+    if (priceRangeIds.length && !priceRangeIds.some((rangeId) => matchesPriceRange(product.price, rangeId))) {
+      return false;
+    }
+
+    return true;
+  });
+}
