  status: RequestStatus;
  errorMessage: string;
  products: PreparedProduct[];
  availableCategories: string[];
  searchTerm: string;
  selectedCategories: string[];
  selectedPriceRanges: string[];
  hasHydratedFromUrl: boolean;
  hydrateFiltersFromUrl: (search: string) => void;
  setLoading: () => void;
  setProducts: (products: Product[]) => void;
  setError: (message: string) => void;
  setSearchTerm: (value: string) => void;
  toggleCategory: (category: string) => void;
  togglePriceRange: (rangeId: string) => void;
  removeCategory: (category: string) => void;
  removePriceRange: (rangeId: string) => void;
  clearFilters: () => void;
};

function toggleValue(list: string[], value: string) {
  return list.includes(value) ? list.filter((entry) => entry !== value) : [...list, value];
}

export const useProductFilterStore = create<ProductFilterStore>((set) => ({
  status: 'idle',
  errorMessage: '',
  products: [],
  availableCategories: [],
  searchTerm: '',
  selectedCategories: [],
  selectedPriceRanges: [],
  hasHydratedFromUrl: false,
  hydrateFiltersFromUrl: (search) => {
    const nextFilters = parseFiltersFromSearch(search);

    set({
      ...nextFilters,
      hasHydratedFromUrl: true,
    });
  },
  setLoading: () =>
    set({
      status: 'loading',
      errorMessage: '',
    }),
  setProducts: (products) =>
    set({
      status: 'success',
      errorMessage: '',
      products: prepareProducts(products),
      availableCategories: deriveCategories(products),
    }),
  setError: (message) =>
    set({
      status: 'error',
      errorMessage: message,
    }),
  setSearchTerm: (value) =>
    set({
      searchTerm: value,
    }),
  toggleCategory: (category) =>
    set((state) => ({
      selectedCategories: toggleValue(state.selectedCategories, category),
    })),
  togglePriceRange: (rangeId) =>
    set((state) => ({
      selectedPriceRanges: toggleValue(state.selectedPriceRanges, rangeId),
    })),
  removeCategory: (category) =>
    set((state) => ({
      selectedCategories: state.selectedCategories.filter((entry) => entry !== category),
    })),
  removePriceRange: (rangeId) =>
    set((state) => ({
      selectedPriceRanges: state.selectedPriceRanges.filter((entry) => entry !== rangeId),
    })),
  clearFilters: () =>
    set({
      searchTerm: '',
      selectedCategories: [],
      selectedPriceRanges: [],
    }),
}));

