 15	
 16	  return value
 17	    .split(',')
 18	    .map((entry) => entry.trim())
 19	    .filter(Boolean);
 20	}
 21	
 22	function normalizeList(values: string[]) {
 23	  return [...new Set(values)].sort((left, right) => left.localeCompare(right, 'ko-KR'));
 24	}
 25	
 26	export function prepareProducts(products: Product[]): PreparedProduct[] {
 27	  return products.map((product) => ({
 28	    ...product,
 29	    searchIndex: product.name.toLocaleLowerCase('ko-KR'),
 30	  }));
 31	}
 32	
 33	export function deriveCategories(products: Product[]) {
 34	  return normalizeList(products.map((product) => product.category));
 35	}
