 37	export function parseFiltersFromSearch(search: string): FilterSnapshot {
 38	  const params = new URLSearchParams(search);
 39	
 40	  return {
 41	    searchTerm: params.get('q')?.trim() ?? '',
 42	    selectedCategories: normalizeList(parseList(params.get('categories'))),
 43	    selectedPriceRanges: normalizeList(parseList(params.get('prices'))),
 44	  };
 45	}
 46	
 47	export function serializeFiltersToSearch(filters: FilterSnapshot) {
 48	  const params = new URLSearchParams();
 49	
 50	  if (filters.searchTerm.trim()) {
 51	    params.set('q', filters.searchTerm.trim());
 52	  }
 53	
 54	  if (filters.selectedCategories.length) {
 55	    params.set('categories', normalizeList(filters.selectedCategories).join(','));
 56	  }
 57	
 58	  if (filters.selectedPriceRanges.length) {
 59	    params.set('prices', normalizeList(filters.selectedPriceRanges).join(','));
