import React from 'react';
import { FixedSizeList, ListChildComponentProps } from 'react-window';
import { useElementHeight } from '../hooks/useElementHeight';
import { formatPrice } from '../lib/filters';
import type { PreparedProduct } from '../types';

type ProductListProps = {
  products: PreparedProduct[];
  status: 'idle' | 'loading' | 'success' | 'error';
  errorMessage: string;
};

type RowData = {
  products: PreparedProduct[];
};

const ROW_HEIGHT = 104;

const ProductRow = React.memo(({ data, index, style }: ListChildComponentProps<RowData>) => {
  const product = data.products[index];

  return (
    <div style={style} className="product-row-shell">
      <article className="product-row">
        <div className="product-row__identity">
          <span className="product-row__index">{String(product.id).padStart(5, '0')}</span>
          <div>
            <h3>{product.name}</h3>
            <p>{product.category}</p>
          </div>
        </div>
        <strong>{formatPrice(product.price)}</strong>
      </article>
    </div>
  );
});

export function ProductList({ products, status, errorMessage }: ProductListProps) {
  const { ref, height } = useElementHeight<HTMLDivElement>();

  if (status === 'loading' || status === 'idle') {
    return (
      <div className="status-card">
        <strong>상품 목록을 불러오는 중입니다.</strong>
        <p>정적으로 생성된 JSON을 mock API처럼 fetch하고 있습니다.</p>
      </div>
    );
  }

  if (status === 'error') {
    return (
      <div className="status-card status-card--error">
        <strong>데이터 로딩에 실패했습니다.</strong>
        <p>{errorMessage}</p>
      </div>
    );
  }

  if (!products.length) {
    return (
      <div className="status-card">
        <strong>조건에 맞는 상품이 없습니다.</strong>
        <p>검색어를 줄이거나 카테고리/가격 필터를 일부 해제해 보세요.</p>
      </div>
    );
  }

  return (
    <div className="product-list-frame" ref={ref}>
      {height > 0 ? (
        <FixedSizeList
          className="product-list"
          height={height}
          itemCount={products.length}
          itemData={{ products }}
          itemKey={(index, data) => data.products[index].id}
          itemSize={ROW_HEIGHT}
          overscanCount={8}
          width="100%"
        >
          {ProductRow}
        </FixedSizeList>
      ) : null}
    </div>
  );
}

import React from 'react';
import { FilterPanel } from './components/FilterPanel';
import { ProductList } from './components/ProductList';
import { filterProducts, serializeFiltersToSearch } from './lib/filters';
import { fetchProducts } from './lib/mockApi';
import { useProductFilterStore } from './store/useProductFilterStore';
import './App.css';

function App() {
  const status = useProductFilterStore((state) => state.status);
  const errorMessage = useProductFilterStore((state) => state.errorMessage);
  const products = useProductFilterStore((state) => state.products);
  const availableCategories = useProductFilterStore((state) => state.availableCategories);
  const searchTerm = useProductFilterStore((state) => state.searchTerm);
  const selectedCategories = useProductFilterStore((state) => state.selectedCategories);
  const selectedPriceRanges = useProductFilterStore((state) => state.selectedPriceRanges);
  const hasHydratedFromUrl = useProductFilterStore((state) => state.hasHydratedFromUrl);
  const hydrateFiltersFromUrl = useProductFilterStore((state) => state.hydrateFiltersFromUrl);
  const setLoading = useProductFilterStore((state) => state.setLoading);
  const setProducts = useProductFilterStore((state) => state.setProducts);
  const setError = useProductFilterStore((state) => state.setError);

  React.useEffect(() => {
    hydrateFiltersFromUrl(window.location.search);
  }, [hydrateFiltersFromUrl]);

  React.useEffect(() => {
    const controller = new AbortController();

    async function loadProducts() {
      setLoading();

      try {
        const loadedProducts = await fetchProducts(controller.signal);
        setProducts(loadedProducts);
      } catch (error) {
        if (controller.signal.aborted) {
          return;
        }

        const nextMessage = error instanceof Error ? error.message : '상품 데이터를 불러오지 못했습니다.';
        setError(nextMessage);
      }
    }

    loadProducts();

    return () => controller.abort();
  }, [setError, setLoading, setProducts]);

  React.useEffect(() => {
    if (!hasHydratedFromUrl) {
      return;
    }

    const nextSearch = serializeFiltersToSearch({
      searchTerm,
      selectedCategories,
      selectedPriceRanges,
    });

    const nextUrl = nextSearch ? `${window.location.pathname}?${nextSearch}` : window.location.pathname;
    const currentUrl = `${window.location.pathname}${window.location.search}`;

    if (nextUrl !== currentUrl) {
      window.history.replaceState({}, '', nextUrl);
    }
  }, [hasHydratedFromUrl, searchTerm, selectedCategories, selectedPriceRanges]);

  const filteredProducts = React.useMemo(
    () =>
      filterProducts(products, {
        searchTerm,
        selectedCategories,
        selectedPriceRanges,
      }),
    [products, searchTerm, selectedCategories, selectedPriceRanges]
  );

  const activeFilterCount =
    selectedCategories.length + selectedPriceRanges.length + (searchTerm.trim() ? 1 : 0);

  return (
    <div className="page-shell">
      <div className="page-glow page-glow-left" />
      <div className="page-glow page-glow-right" />

      <header className="hero">
        <div>
          <p className="eyebrow">Static Mock API + Zustand + URL Sync</p>
          <h1>10,000개 상품을 빠르게 필터링하는 UI</h1>
          <p className="hero-copy">
            정적으로 생성한 JSON을 fetch하고, 검색어와 다중 선택 필터를 URL 쿼리로 유지하며,
            결과 목록은 가상화 렌더링으로 처리합니다.
          </p>
        </div>

        <div className="hero-stats">
          <div>
            <strong>{products.length.toLocaleString('ko-KR')}</strong>
            <span>총 상품 수</span>
          </div>
          <div>
            <strong>{filteredProducts.length.toLocaleString('ko-KR')}</strong>
            <span>현재 결과</span>
          </div>
          <div>
            <strong>{activeFilterCount}</strong>
            <span>활성 필터</span>
          </div>
        </div>
      </header>

      <main className="workspace">
        <FilterPanel
          availableCategories={availableCategories}
          resultCount={filteredProducts.length}
          totalCount={products.length}
        />

        <section className="results-panel">
          <div className="results-panel__header">
            <div>
              <p className="results-panel__eyebrow">Performance Notes</p>
              <h2>가상화된 결과 목록</h2>
            </div>
            <p className="results-panel__hint">
              필터는 메모이즈된 계산으로 처리하고, 화면에는 보이는 행만 렌더링합니다.
            </p>
          </div>

          <ProductList products={filteredProducts} status={status} errorMessage={errorMessage} />
        </section>
      </main>
    </div>
  );
}

export default App;

