payload.aggregated_output:
import React from 'react';
import { PRICE_RANGES } from '../lib/filters';
import { useProductFilterStore } from '../store/useProductFilterStore';

type FilterPanelProps = {
  availableCategories: string[];
  resultCount: number;
  totalCount: number;
};

export function FilterPanel({ availableCategories, resultCount, totalCount }: FilterPanelProps) {
  const searchTerm = useProductFilterStore((state) => state.searchTerm);
  const selectedCategories = useProductFilterStore((state) => state.selectedCategories);
  const selectedPriceRanges = useProductFilterStore((state) => state.selectedPriceRanges);
  const setSearchTerm = useProductFilterStore((state) => state.setSearchTerm);
  const toggleCategory = useProductFilterStore((state) => state.toggleCategory);
  const togglePriceRange = useProductFilterStore((state) => state.togglePriceRange);
  const removeCategory = useProductFilterStore((state) => state.removeCategory);
  const removePriceRange = useProductFilterStore((state) => state.removePriceRange);
  const clearFilters = useProductFilterStore((state) => state.clearFilters);

  const hasActiveFilters =
    Boolean(searchTerm.trim()) || selectedCategories.length > 0 || selectedPriceRanges.length > 0;

  return (
    <aside className="filter-panel">
      <div className="filter-panel__intro">
        <p className="eyebrow">Filter Controls</p>
        <h2>검색과 다중 선택 필터</h2>
        <p>카테고리와 가격 범위를 동시에 선택하고, 현재 상태를 URL 쿼리로 유지합니다.</p>
      </div>

      <div className="filter-block">
        <label className="filter-label" htmlFor="product-search">
          상품 검색
        </label>
        <input
          id="product-search"
          className="search-input"
          type="search"
          value={searchTerm}
          onChange={(event) => setSearchTerm(event.target.value)}
          placeholder="예: 스마트 노트북, 시그니처 세럼"
        />
      </div>

      <div className="filter-block">
        <div className="filter-block__header">
          <span className="filter-label">카테고리</span>
          <span className="filter-meta">{selectedCategories.length}개 선택</span>
        </div>
        <div className="filter-chip-grid">
          {availableCategories.map((category) => {
            const isSelected = selectedCategories.includes(category);

            return (
              <button
                key={category}
                type="button"
                className={`filter-chip ${isSelected ? 'is-active' : ''}`}
                onClick={() => toggleCategory(category)}
              >
                {category}
              </button>
            );
          })}
        </div>
      </div>

      <div className="filter-block">
        <div className="filter-block__header">
          <span className="filter-label">가격 범위</span>
          <span className="filter-meta">{selectedPriceRanges.length}개 선택</span>
        </div>
        <div className="filter-chip-grid">
          {PRICE_RANGES.map((range) => {
            const isSelected = selectedPriceRanges.includes(range.id);

            return (
              <button
                key={range.id}
                type="button"
                className={`filter-chip ${isSelected ? 'is-active' : ''}`}
                onClick={() => togglePriceRange(range.id)}
              >
                {range.label}
              </button>
            );
          })}
        </div>
      </div>

      <div className="filter-summary">
        <div>
          <strong>{resultCount.toLocaleString('ko-KR')}</strong>
          <span>필터 결과</span>
        </div>
        <div>
          <strong>{totalCount.toLocaleString('ko-KR')}</strong>
          <span>전체 상품</span>
        </div>
      </div>

      <div className="active-filters">
        <div className="filter-block__header">
          <span className="filter-label">선택된 필터</span>
          <button
            type="button"
            className="clear-button"
            onClick={clearFilters}
            disabled={!hasActiveFilters}
          >
            전체 초기화
          </button>
        </div>

        <div className="active-filter-list">
          {searchTerm.trim() ? (
            <button type="button" className="active-filter-pill" onClick={() => setSearchTerm('')}>
              검색어: {searchTerm}
            </button>
          ) : null}

          {selectedCategories.map((category) => (
            <button
              key={category}
              type="button"
              className="active-filter-pill"
              onClick={() => removeCategory(category)}
            >
              카테고리: {category}
            </button>
          ))}

          {selectedPriceRanges.map((rangeId) => {
            const label = PRICE_RANGES.find((range) => range.id === rangeId)?.label ?? rangeId;

            return (
              <button
                key={rangeId}
                type="button"
                className="active-filter-pill"
                onClick={() => removePriceRange(rangeId)}
              >
                가격: {label}
              </button>
            );
          })}

          {!hasActiveFilters ? <p className="active-filter-empty">아직 선택된 필터가 없습니다.</p> : null}
        </div>
      </div>
    </aside>
  );
}

