import React from 'react';
import { FixedSizeList, ListChildComponentProps } from 'react-window';
import { useElementHeight } from '../hooks/useElementHeight';
import { formatPrice } from '../lib/filters';
import type { PreparedProduct } from '../types';

type ProductListProps = {
  products: PreparedProduct[];
  status: 'idle' | 'loading' | 'success' | 'error';
  errorMessage: string;
};

type RowData = {
  products: PreparedProduct[];
};

const ROW_HEIGHT = 104;

const ProductRow = React.memo(({ data, index, style }: ListChildComponentProps<RowData>) => {
  const product = data.products[index];

  return (
    <div style={style} className="product-row-shell">
      <article className="product-row">
        <div className="product-row__identity">
          <span className="product-row__index">{String(product.id).padStart(5, '0')}</span>
          <div>
            <h3>{product.name}</h3>
            <p>{product.category}</p>
          </div>
        </div>
        <strong>{formatPrice(product.price)}</strong>
      </article>
    </div>
  );
});

export function ProductList({ products, status, errorMessage }: ProductListProps) {
  const { ref, height } = useElementHeight<HTMLDivElement>();
  const listHeight = height > 0 ? height : 520;

  if (status === 'loading' || status === 'idle') {
    return (
      <div className="status-card">
        <strong>상품 목록을 불러오는 중입니다.</strong>
        <p>정적으로 생성된 JSON을 mock API처럼 fetch하고 있습니다.</p>
      </div>
    );
  }

  if (status === 'error') {
    return (
      <div className="status-card status-card--error">
        <strong>데이터 로딩에 실패했습니다.</strong>
        <p>{errorMessage}</p>
      </div>
    );
  }

  if (!products.length) {
    return (
      <div className="status-card">
        <strong>조건에 맞는 상품이 없습니다.</strong>
        <p>검색어를 줄이거나 카테고리/가격 필터를 일부 해제해 보세요.</p>
      </div>
    );
  }

  return (
    <div className="product-list-frame" ref={ref}>
      <div className="product-list-summary">
        <strong>{products.length.toLocaleString('ko-KR')}개 결과</strong>
        <span>필터링된 상품이 아래 목록에 표시됩니다.</span>
      </div>

      {products.length > 0 ? (
        <FixedSizeList
          className="product-list"
          height={listHeight}
          itemCount={products.length}
          itemData={{ products }}
          itemKey={(index, data) => data.products[index].id}
          itemSize={ROW_HEIGHT}
          overscanCount={8}
          width="100%"
        >
          {ProductRow}
        </FixedSizeList>
      ) : null}
    </div>
  );
}

