  font-size: clamp(2.3rem, 4vw, 4.4rem);
}

.hero-copy {
  max-width: 62ch;
  margin: 18px 0 0;
  line-height: 1.7;
  color: var(--muted);
}

.hero-stats {
  display: grid;
  gap: 14px;
}

.hero-stats div {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 18px 20px;
  border: 1px solid rgba(141, 57, 21, 0.08);
  border-radius: 22px;
  background: rgba(255, 248, 241, 0.8);
}

.hero-stats strong {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 1.9rem;
}

.hero-stats span {
  color: var(--muted);
  font-size: 0.95rem;
}

.workspace {
  display: grid;
  grid-template-columns: minmax(300px, 360px) minmax(0, 1fr);
  gap: 24px;
  margin-top: 24px;
}

.results-panel {
  display: flex;
  flex-direction: column;
  min-height: 720px;
  border: 1px solid var(--line);
  border-radius: 32px;
  padding: 24px;
  background: var(--surface);
  box-shadow: var(--shadow);
  backdrop-filter: blur(14px);
}

.results-panel__header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 24px;
  margin-bottom: 20px;
}

.results-panel__hint {
  max-width: 26ch;
  margin: 0;
  line-height: 1.6;
  text-align: right;
  color: var(--muted);
}

.filter-panel {
  display: flex;
  flex-direction: column;
  gap: 20px;
  padding: 24px;
  border: 1px solid var(--line);
  border-radius: 32px;
  background: rgba(255, 251, 245, 0.84);
  box-shadow: var(--shadow);
}

.filter-panel__intro h2 {
  margin: 0;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 1.8rem;
}

.filter-panel__intro p:last-child {
  margin: 12px 0 0;
  color: var(--muted);
  line-height: 1.6;
}

.filter-block {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.filter-block__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.filter-label {
  font-size: 0.95rem;
  font-weight: 700;
}

.filter-meta {
  color: var(--muted);
  font-size: 0.85rem;
}

.search-input {
  width: 100%;
  padding: 14px 16px;
  border: 1px solid rgba(80, 56, 31, 0.14);
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.9);
  color: var(--text);
}

.search-input:focus {
  outline: 2px solid rgba(199, 92, 45, 0.2);
  border-color: rgba(199, 92, 45, 0.28);
}

.filter-chip-grid,
.active-filter-list {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.filter-chip,
.active-filter-pill,
.clear-button {
  border: 1px solid rgba(80, 56, 31, 0.12);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.88);
  color: var(--text);
  transition:
    background 150ms ease,
    border-color 150ms ease,
    transform 150ms ease;
}

.filter-chip {
  padding: 10px 14px;
}

.filter-chip:hover,
.active-filter-pill:hover,
.clear-button:hover:not(:disabled) {
  transform: translateY(-1px);
}

.filter-chip.is-active,
.active-filter-pill {
  background: rgba(199, 92, 45, 0.12);
  border-color: rgba(199, 92, 45, 0.34);
}

.filter-summary {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
}

.filter-summary div {
  padding: 16px;
  border-radius: 22px;
  background: rgba(255, 248, 241, 0.92);
}

.filter-summary strong {
  display: block;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 1.4rem;
}

.filter-summary span,
.active-filter-empty {
  color: var(--muted);
}

.clear-button {
  padding: 10px 14px;
}

.clear-button:disabled {
  cursor: default;
  opacity: 0.48;
}

.active-filter-pill {
  padding: 10px 14px;
}

.product-list-frame {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
}

.product-list-summary {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 14px;
  padding: 14px 16px;
  border: 1px solid rgba(80, 56, 31, 0.08);
  border-radius: 18px;
  background: rgba(255, 248, 241, 0.92);
}

.product-list-summary strong {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 1rem;
}

.product-list-summary span {
  color: var(--muted);
  font-size: 0.92rem;
}

.product-list {
  flex: 1;
  overflow-x: hidden !important;
}

.product-row-shell {
  padding: 0 0 12px;
}

.product-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  height: calc(100% - 12px);
  padding: 20px;
  border: 1px solid rgba(80, 56, 31, 0.08);
  border-radius: 24px;
  background: rgba(255, 255, 255, 0.92);
}

